#include <iostream>
using namespace std;
int n,p,a[5000005],s[5000005],ans[5000005],minn=105;
int main()
{
    cin>>n>>p;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
        s[i]=a[i]-a[i-1];
    }
    for(int i=0;i<=p-1;i++)
    {
        int x,y,z;
        cin>>x>>y>>z;
        s[x]+=z;
        s[y+1]-=z;
    }
    for(int i=1;i<=n;i++)
    {
        ans[i]=ans[i-1]+s[i];
        if(ans[i]<minn)
        {
            minn=ans[i];
        }
    }
    cout<<minn;
}
